import institutionRegistryData from "./generated/institutionRegistry.json" with { type: "json" };

/**
 * Auto-detected institution registry seam (Step 3 of the global data/image
 * expansion plan - see docs/GLOBAL_DATA_AND_IMAGE_EXPANSION_PLAN.md).
 * Regenerated by scripts/ingestion/buildInstitutionRegistry.mjs from the
 * app's actual research records - not hand-maintained.
 *
 * Not yet wired into InstitutionDetail.jsx/InstitutionHeader.jsx (those
 * still use researchProjectData.js's institutionsBySlug, built directly
 * from the legacy dataset) - this is the data layer the frontend can move
 * onto next, once the registry has been reviewed.
 */
export const institutionRegistry = institutionRegistryData.institutions ?? [];

const bySlug = new Map(institutionRegistry.map((entry) => [entry.slug, entry]));
const byNormalizedName = new Map(institutionRegistry.map((entry) => [entry.normalizedName, entry]));

export function getInstitutionRegistryEntry({ slug, name } = {}) {
  if (slug && bySlug.has(slug)) return bySlug.get(slug);
  if (name) {
    const key = name
      .toLowerCase()
      .replace(/[^a-z0-9]+/g, " ")
      .trim();
    if (byNormalizedName.has(key)) return byNormalizedName.get(key);
  }
  return null;
}

export const institutionRegistryMeta = {
  generatedAt: institutionRegistryData.generatedAt,
  totalInstitutions: institutionRegistryData.totalInstitutions,
  withRecords: institutionRegistryData.withRecords,
  withOfficialWebsite: institutionRegistryData.withOfficialWebsite,
  withImageReady: institutionRegistryData.withImageReady,
};
